const projects = $input.first().json.data;

 if (projects.length === 0) {
   return [{ json: { skip: true } }];
 }

// Split projects by health
const splitProjects = {
  Green: [],
  Amber: [],
  Red: []
};

projects.forEach(project => {
  const health = project.property_health || 'Green';

  const projectData = {
    projectId: project.id,
    projectUrl: project.url,
    projectCode: project.property_project_code,
    projectName: project.property_project_name,
    currentHealth: health,
    internalLeadEmail: project.property_internal_lead_email,
    internalLeadName: project.property_internal_lead_name
  };

  if (splitProjects[health]) {
    splitProjects[health].push(projectData);
  } else {
    // If health is something unexpected, put it in Red by default
    splitProjects.Red.push(projectData);
  }
});

return splitProjects;

