let records = $('Records').all();
let actions = $('Actions').all();
let projects = $('Get many database pages').all();

let type = ['SI', 'DCN', 'VO'];

// --------------------
// Group records by project code
// --------------------
let recordsByProject = {};
records.forEach(record => {
  let code = record.json.property_reference?.split('-')[0];
  if (!code) return;

  if (!recordsByProject[code]) recordsByProject[code] = [];
  recordsByProject[code].push(record);
});

// --------------------
// Group actions by project code
// --------------------
let actionsByProject = {};
actions.forEach(action => {
  let code = action.json.property_title?.split('-')[0];
  if (!code) return;

  if (!actionsByProject[code]) actionsByProject[code] = [];
  actionsByProject[code].push(action);
});

// --------------------
// Enrich projects with suggested health
// --------------------
let enrichedProjects = projects.map(project => {
  let projectCode = project.json.property_project_code;

  let critical_actions = 0;
  let aging_records = 0;
  let blocked_actions = 0;
  let overdue_rfis = 0;

  // -------- Records --------
  (recordsByProject[projectCode] || []).forEach(record => {
    if (
      (record.json.property_priority === 'P1 Critical' ||
       record.json.property_priority === 'P2 High') &&
      record.json.property_days_until_due < 0
    ) {
      critical_actions++;
    }

    if (
      record.json.property_status === 'Issued' &&
      record.json.property_acknowledgment_date == null &&
      type.includes(record.json.property_record_type)
    ) {
      aging_records++;
    }
  });

  // -------- Actions --------
  (actionsByProject[projectCode] || []).forEach(action => {
    let ref = action.json.property_title || '';

    if (action.json.property_status === 'Blocked') {
      blocked_actions++;
    }

    if (ref.includes('RFI') && action.json.property_days_until_due < 0) {
      overdue_rfis++;
    }
  });

  // -------- Score & Health --------
  let score = 0;
  if (critical_actions > 0) score += critical_actions * 10;
  if (aging_records > 2) score += aging_records * 5;
  if (blocked_actions > 0) score += blocked_actions * 7;
  if (overdue_rfis > 0) score += overdue_rfis * 8;

  let suggested_health;
  if (score >= 30) suggested_health = "Red";
  else if (score >= 15) suggested_health = "Amber";
  else suggested_health = "Green";

  // 🔹 Return original project + suggested health
  return {
    ...project.json,
    suggested_health
  };
});

// --------------------
// Final Return (ALL projects only)
// --------------------
return enrichedProjects;
